var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"합중국, 롱 혼 자치구 – 16:42:07\\n마리아 안토노프 중장, <color=#ffd34c>만타레이 교도소 면회실</color>\\nCSE Lv. <b>0</b>","JPN":"合衆国、ロング・ホーン自治区　–　16:42:07\\nマリア・アントノフ中将、<color=#ffd34c>マンタレー刑務所面会室</color>\\nCSE Lv.<b>0</b>","ENG":"The States, Long Horn Autonomous Region – 16:42:07\\nLieutenant General Maria Antonov, <color=#ffd34c>Manta Ray Prison Visiting Room</color>\\nCSE Lv. <b>0</b>","TWN":"合眾國 倫霍恩自治區 – 16:42:07\\n瑪麗亞·安東諾夫中將，<color=#ffd34c>曼塔雷監獄接見室</color>\\nCSE Lv. <b>0</b>","THA":"อเมริกา เขตปกครองตัวเองลองฮอร์น – 16:42:07\\nพลโทมาเรีย แอนโทนอฟ <color=#ffd34c>ห้องเยี่ยมผู้ต้องขัง เรือนจำแมนทาเรย์</color>\\nระดับ CSE <b>0</b>","VTN":"The States, Khu Tự Trị Long Horn - 16:42:07 \\nTrung Tướng Maria Antonov, <color=#ffd34c>Phòng Thăm Tù Manta Ray</color>\\nCSE Cấp <b>0</b>","SCN":"联邦，长角自治区 - 16:42:07\\n玛丽亚·安东中将，<color=#ffd34c>曼塔雷教导所探监室</color>\\nCSE Lv. <b>0</b>","DEU":"USA, Autonome Region Long Horn – 16:42:07\\nGeneralleutnantin Maria Antonow, <color=#ffd34c>Besuchsraum des Manta Ray-Gefängnisses</color>\\nCSE-St.: <b>0</b>","FRA":"États-Unis, région autonome de Long Horn - 16:42:07\\nLieutenante générale Maria Antonov, <color=#ffd34c>Parloir de la prison Manta Ray</color>\\nECM Niv. <b>0</b>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"수감 번호 1677번. 면회다.","JPN":"囚人番号1677番。面会だ。","ENG":"Prisoner #1677, you have a visitor.","TWN":"1677，有人來見你。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"수감 번호 1677번! 면회다! 즉시 일어서서 벽을 바라보고 서라!","JPN":"囚人番号1677番！　面会だ！　今すぐ壁を向いて立て！","ENG":"Prisoner #1677! You have a visitor! Stand up and face the wall right now!","TWN":"1677！立刻起來面壁站好！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"그렇지 않으면……","JPN":"さもなければ……","ENG":"Or else...","TWN":"否則……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 괜찮아. 그보다 둘만 있게 해 주게.","JPN":"いや、いいんだ。それより二人きりにしてくれ。","ENG":"It’s quite alright. Leave us.","TWN":"沒關係，你先退下，留我們兩個就好。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"하지만 중장님, 아시다시피 수감 번호 1677번은…….","JPN":"しかし中将、ご存知のとおり囚人番号1677番は……","ENG":"But Lieutenant General, as you know, Prisoner #1677 is...","TWN":"可是中將您也知道1677她……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"괜찮다고 했네. 날 믿지 못하는 건가?","JPN":"いいと言ったはずだ。それとも、私のことが信用できないのか？","ENG":"I said it’s okay. Is there a problem?","TWN":"我說了沒關係，你現在是在質疑我？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRISON_NPC_NULL_NULL","text":{"KOREA":"……그럴 리가요. 부디 조심하십시오.","JPN":"……とんでもありません。どうかお気をつけください。","ENG":"No, ma’am. Please be careful.","TWN":"……不敢！那請中將務必小心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"고맙네.","JPN":"ありがとう。","ENG":"Thank you.","TWN":"謝謝。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"잘 지냈나, 제이나.","JPN":"元気にしていたか、ジェイナ。","ENG":"How have you been, Jaina?","TWN":"婕娜，你好嗎？"},"stage":{"bg":"MAINSTREAM_801","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"안색이 많이 나쁘군. 혹시 그 사이 새로운 기억이라도 떠오른 건가.","JPN":"顔色が悪いな。\\nもしや、何か新しい記憶を思い出したのか？","ENG":"You don’t look well. Some new memory come up?","TWN":"你的臉色不太好，又有新的記憶浮現嗎？"},"stage":{"bg":"MAINSTREAM_801","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……네, 안토노프 <color=#ffd34c>대령</color>님.","JPN":"……はい、アントノフ<color=#ffd34c>大佐</color>。","ENG":"Yes, <color=#ffd34c>Colonel</color> Antonov.","TWN":"……是的，安東諾夫 <color=#ffd34c>上校</color>。"},"stage":{"bg":"MAINSTREAM_801","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"좋았던 시절이 생각 나는 호칭이로군.","JPN":"古き良き時代を思い出させる呼び名だな。","ENG":"“Colonel”, that reminds me of the good old days.","TWN":"這個稱呼令我想起過去美好的時光呢。"},"stage":{"bg":"MAINSTREAM_801","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전황은 어려웠고 힘든 일도 많았지만, 젊은 혈기에 나름 희망도 있었고…….","JPN":"戦況は厳しく、大変なことも多かったが、まだ若かった頃で希望も残っていたな……","ENG":"The war was tough, but I was young and hopeful back then...","TWN":"雖然戰況很艱難、很辛苦，但是因為年輕氣盛，所以還是滿懷著希望……"},"stage":{"bg":"MAINSTREAM_801","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"무엇보다 목숨을 맡길 수 있는 동료들이 곁에 있었지.","JPN":"何より、傍には命を預けられる仲間たちがいた。","ENG":"And I also had comrades that I could rely on.","TWN":"更重要的是，身旁有一群可以同生共死的夥伴。"},"stage":{"bg":"MAINSTREAM_801","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_801","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 지금은 그저 은퇴할 날만 기다리는 늙은이야.","JPN":"今は引退する日を待つばかりの老いぼれだがな。","ENG":"But now I’m nothing but an old woman who’s waiting for retirement.","TWN":"但現在的我就只是個快要退休的老人。"},"stage":{"bg":"MAINSTREAM_801","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};